import{_ as o,o as t,c as n,ag as p}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"开启俄国近代化的开端：彼得一世改革（地主","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-29.md","filePath":"notes/note-29.md"}'),e={name:"notes/note-29.md"};function r(s,a,l,c,d,i){return t(),n("div",null,[...a[0]||(a[0]=[p('<h1 id="开启俄国近代化的开端-彼得一世改革-地主" tabindex="-1">开启俄国近代化的开端：彼得一世改革（地主 <a class="header-anchor" href="#开启俄国近代化的开端-彼得一世改革-地主" aria-label="Permalink to &quot;开启俄国近代化的开端：彼得一世改革（地主&quot;">​</a></h1><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">开启俄国近代化的开端：</span>彼得一世改革（地主阶级性质的改革）。</p><p>农奴制改革（亚历山大二世） 1861年</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">目的：</span>维护地主阶级的利益 性质：自上而下资产阶级改革</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">影响：</span>历史上的转折点；促使社会的各个方面出现了新气象；推动俄国走上发展资本主义的道路。农奴制残余影响俄国经济与社会发展。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">美国南北战争：</span>1861-1865年 领导人：林肯</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">内战转折点：</span>《宅地法》《解放黑人奴隶宣言》</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">《宅》《解》的意义：</span>调动农民和黑奴参战积极性，扭转了北方军队在战场上的被动局面，是美国内战转折点。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">影响：</span>美国历史上第二次资产阶级革命，维护了国家统一，废除奴隶制，清除了美国资本主义发展的最大障碍，为经济迅速发展创造了条件 。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">日本明治维新：</span>1868年 性质：资产阶级改革</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">内容：</span>（政）废藩置县；（经）以殖产兴业为口号，发展近代经济；（社会生活）文明开化。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">评价：</span>摆脱民族危机，使日本走上发展资本主义道路，实现富国强兵，开始跻身资本主义强国之列。保留旧制度残余，军国主义色彩浓厚，走上对外侵略道路。</p>',12)])])}const _=o(e,[["render",r]]);export{v as __pageData,_ as default};
